#include <bits/stdc++.h>
using namespace std; 
stack<int> p;
int n=52,m,d[53],g[53][53];
void Read(){
	cin>>m;
	for(int i=1;i<=m;i++){
		string s;
		cin>>s;
		char a=s[0],b=s[1];
		g[(a>='A' && a<='Z')? a-'A':a-'a'+26][(b>='A' && b<='Z')? b-'A':b-'a'+26]=1;
		g[(b>='A' && b<='Z')? b-'A':b-'a'+26][(a>='A' && a<='Z')? a-'A':a-'a'+26]=1;
		d[(a>='A' && a<='Z')? a-'A':a-'a'+26]++,d[(b>='A' && b<='Z')? b-'A':b-'a'+26]++;
	}
}
void dfs(int x){
	for(int i=0;i<52;i++)
		if(g[x][i]){
			g[x][i]=g[i][x]=0;
			dfs(i);
		}
	p.push(x);
}
void Solve(){
	int x=-1,f=-1,y=0;
	for(int i=0;i<52;i++){
		if(d[i] && f==-1)
			f=i;
		if(d[i]%2==1){
			y++;
			if(x==-1)
				x=i;
		}
	}
	if(!(y==2 || y==0)){
		cout<<"No Solution";
		return;
	}
	if(y)
		dfs(x);
	else
		dfs(f);
	if(p.size()<m+1){
		cout<<"No Solution";
		return;
	}
	while(p.size()){
		cout<<char(p.top()<26? 'A'+p.top():'a'+p.top()-26);
		p.pop();
	}
}
int main(){
	Read();
	Solve();
	return 0;
}
